definition.script:
pipeline {
  agent any
  stages {
    stage('Deploy PSAMA') {
      steps {
        build job: 'PIC-SURE Wildfly Stack Deploy', parameters: [
          [$class: 'StringParameterValue', name: 'S3_BUCKET_NAME', value: params.S3_STACK_BUCKET],
          [$class: 'StringParameterValue', name: 'TARGET_STACK', value: params.TARGET_STACK],
          [$class: 'StringParameterValue', name: 'DATASET_S3_OBJECT_KEY', value: String.valueOf(params.DATASET_S3_OBJECT_KEY)],
          [$class: 'StringParameterValue', name: 'ENABLE_DEBUG', value: String.valueOf(params.ENABLE_DEBUG)],
          [$class: 'StringParameterValue', name: 'SPRING_PROFILE', value: String.valueOf(params.SPRING_PROFILE)],
          [$class: 'BooleanParameterValue', name: 'DEPLOY_API', value: false],
          [$class: 'BooleanParameterValue', name: 'DEPLOY_PSAMA', value: true],
          [$class: 'BooleanParameterValue', name: 'DEPLOY_DICTIONARY', value: false]
        ]
      }
    }
  }
}
